        //         D: 0,
        //         V2: 3086.4496105,
        //         T2: 332811624.339836,
        //         F: 0,
        //         C: 0,
        //         BP1: 109344.9,
        //         AP1: 109345.2
        //     }
        //
        let mut timestamp: Value = self.safe_integer_k(ticker.clone(), "U", &[]);
        let mut high: Value = self.safe_number_k(ticker.clone(), "H", &[]);
