        //     }
        //
        let mut timestamp: Value = self.safe_integer_k(position.clone(), "U", &[]);
        let mut direction: Value = self.safe_string_k(position.clone(), "p", &[]);
        let mut marginMode: Value = self.safe_string_k(position.clone(), "i", &[]);
